/**
 *
 * @param instanceMap
 * @param event
 * @constructor
 */
export function ChartZoomListener(instanceMap, event) {
    let eventManager = this;
    let data = eventManager.getData(instanceMap, event.type, event.transform);

    // if data fire
    eventManager.associateBehaviours(instanceMap, event.type, data, event.transform, event);
}
